#include <bits/stdc++.h>
using namespace std;
const int N=4e3+3;
int n,b,u[N],ans,f[2][N][2];
int main(){
    scanf("%d%d",&n,&b);
    for(int i=1;i<=n;i++)
        scanf("%d",&u[i]);
    memset(f,0xcf,sizeof(f));
    f[0][0][0]=0;
    for(int i=1;i<=n;i++){
    	memset(f[i&1],0xcf,sizeof(f[i&1]));
        for(int j=0;j<=b;j++){
            f[i&1][j][0]=max(f[(i&1)^1][j][0],f[(i&1)^1][j][1]);
            if(j)
                f[i&1][j][1]=max(f[(i&1)^1][j-1][0],f[(i&1)^1][j-1][1]+u[i]);
        }
    }
    ans=max(f[n&1][b][0],f[n&1][b][1]);
    memset(f,0xcf,sizeof(f));
    for(int i=1;i<=n;i++){
    	memset(f[i&1],0xcf,sizeof(f[i&1]));
    	if(i==1)
    	    f[1][1][1]=u[1];
        for(int j=0;j<=b;j++){
            f[i&1][j][0]=max(f[(i&1)^1][j][0],f[(i&1)^1][j][1]);
            if(j)
                f[i&1][j][1]=max(f[i&1][j][1],max(f[(i&1)^1][j-1][0],f[(i&1)^1][j-1][1]+u[i]));
        }
    }
    ans=max(ans,f[n&1][b][1]);
    printf("%d",ans);
    return 0;
}
